mod root;

use crate::root::{ATT_CA_X, ATT_CA_Y};
use poseidon::poseidon::bn254;
use sha256::digest;

global CAPDU_LEN: u32 = 40;
global RESP_LEN: u32 = 98;
global TBS_LEN: u32 = 376;
global MSG_LEN: u32 = 130;

global CAPDU_PREFIX: [u8; 24] = [
    0x80, 0x22, 0x00, 0x00, 0x00, 0x00, 0x21, 0x41, 0x04, 0x7f, 0xff, 0x02, 0x06, 0x45, 0x04, 0xf0,
    0x00, 0x00, 0x12, 0x46, 0x01, 0x21, 0x47, 0x10,
];

global RESP_FIX_OFF: [u32; 24] = [
    0, 1, 2, 3, 22, 23, 24, 25, 44, 45, 46, 47, 48, 49, 50, 51, 76, 77, 78, 79, 82, 83, 84, 85,
];
global RESP_FIX_VAL: [u8; 24] = [
    0x41, 0x82, 0x00, 0x12, 0x42, 0x82, 0x00, 0x12, 0x43, 0x82, 0x00, 0x1c, 0x7f, 0xff, 0x02, 0x06,
    0x44, 0x82, 0x00, 0x02, 0x4f, 0x82, 0x00, 0x0c,
];

fn pack_chip(bytes: [u8; 18]) -> Field {
    let mut acc: Field = 0;
    for i in 0..18 {
        acc = acc * 256 + bytes[i] as Field;
    }
    acc
}

fn main(
    capdu: [u8; CAPDU_LEN],
    resp: [u8; RESP_LEN],
    attst_sig: [u8; 64],
    tbs: [u8; TBS_LEN],
    cert_sig: [u8; 64],
    fresh_bind: pub Field,
    enroll_nullifier: pub Field,
) {
    for i in 0..24 {
        assert(capdu[i] == CAPDU_PREFIX[i]);
    }
    for i in 0..24 {
        assert(resp[RESP_FIX_OFF[i]] == RESP_FIX_VAL[i]);
    }
    for i in 0..18 {
        assert(resp[4 + i] == resp[26 + i]);
        assert(tbs[11 + i] == resp[26 + i]);
    }
    assert(tbs[9] == 0x02);
    assert(tbs[10] == 0x14);
    assert(tbs[280] == 0x03);
    assert(tbs[281] == 0x42);
    assert(tbs[282] == 0x00);
    assert(tbs[283] == 0x04);

    let capdu_hash: [u8; 32] = digest(capdu);
    let mut msg: [u8; MSG_LEN] = [0; MSG_LEN];
    for i in 0..32 {
        msg[i] = capdu_hash[i];
    }
    for i in 0..RESP_LEN {
        msg[32 + i] = resp[i];
    }
    let att_hash: [u8; 32] = digest(msg);

    let mut pub_x: [u8; 32] = [0; 32];
    let mut pub_y: [u8; 32] = [0; 32];
    for i in 0..32 {
        pub_x[i] = tbs[284 + i];
        pub_y[i] = tbs[316 + i];
    }
    assert(std::ecdsa_secp256r1::verify_signature(pub_x, pub_y, attst_sig, att_hash));

    let tbs_hash: [u8; 32] = digest(tbs);
    assert(std::ecdsa_secp256r1::verify_signature(ATT_CA_X, ATT_CA_Y, cert_sig, tbs_hash));

    let mut fb: Field = 0;
    for i in 0..16 {
        fb = fb * 256 + capdu[24 + i] as Field;
    }
    assert(fb == fresh_bind);

    let mut chip_id: [u8; 18] = [0; 18];
    for i in 0..18 {
        chip_id[i] = resp[26 + i];
    }
    assert(enroll_nullifier == bn254::hash_1([pack_chip(chip_id)]));
}

